/*
 * sinhf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sinhf  (test_sinhf_opt.elf)
 *   2. Linked with toolchain's default sinhf        (test_sinhf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;
#endif

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += sinhf(vx);
#else
    float r = sinhf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit_u(0x00800000u);  /* FLT_MIN = 2^-126, smallest normal */
    emit_u(0x80800000u);  /* -FLT_MIN */
    emit_u(0x00800001u);  /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);  /* FLT_MAX */
    emit_u(0xff7fffffu);  /* -FLT_MAX */
    emit_u(0x7f7ffffeu);  /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7ffffeu);  /* two ULPs below 1.0 */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    emit(1.0f);
    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    emit_u(0x3f800002u);  /* two ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3effffffu);  /* one ULP below 0.5 */
    emit(0.5f);
    emit_u(0x3f000001u);  /* one ULP above 0.5 */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
    emit(2.0f);
    emit_u(0x40000001u);  /* one ULP above 2.0 */

    /* --- Section 6: Function-specific mathematical constants (14) --- */
    emit_u(0x3f317217u);  /* one ULP below ln2 */
    emit_u(0x3f317218u);  /* ln2 = 0.693147... -> sinh(ln2) = 0.75 */
    emit_u(0x3f317219u);  /* one ULP above ln2 */
    emit_u(0xbf317218u);  /* -ln2 */
    emit(0.25f);          /* sinh(0.25) ~ 0.2526 */
    emit(-0.25f);
    emit(0.75f);          /* sinh(0.75) ~ 0.8224 */
    emit(-0.75f);
    emit(1.5f);           /* sinh(1.5) ~ 2.301 */
    emit(-1.5f);
    emit_u(0x3f490fdbu);  /* pi/4 ~ 0.7854 */
    emit_u(0xbf490fdbu);  /* -pi/4 */
    emit_u(0x3fc90fdbu);  /* pi/2 ~ 1.5708 */
    emit_u(0xbfc90fdbu);  /* -pi/2 */

    /* --- Section 7: Overflow threshold stress, positive (8) --- */
    emit_u(0x42b10000u);  /* 88.5 */
    emit_u(0x42b17220u);  /* 88.7229, near exp overflow boundary */
    emit_u(0x42b20000u);  /* 89.0 */
    emit_u(0x42b2cccdu);  /* 89.4 */
    emit_u(0x42b2d4fbu);  /* one ULP below sinhf overflow threshold (~89.416) */
    emit_u(0x42b2d4fcu);  /* sinhf overflow threshold: 89.4159... */
    emit_u(0x42b2d4fdu);  /* one ULP above sinhf overflow threshold */
    emit(100.0f);         /* well past overflow -> +Inf */

    /* --- Section 8: Overflow threshold stress, negative (8) --- */
    emit_u(0xc2b10000u);  /* -88.5 */
    emit_u(0xc2b17220u);  /* -88.7229 */
    emit_u(0xc2b20000u);  /* -89.0 */
    emit_u(0xc2b2cccdu);  /* -89.4 */
    emit_u(0xc2b2d4fbu);  /* one ULP below -sinhf overflow threshold */
    emit_u(0xc2b2d4fcu);  /* -sinhf overflow threshold */
    emit_u(0xc2b2d4fdu);  /* one ULP above -sinhf overflow threshold */
    emit(-100.0f);        /* well past -overflow -> -Inf */

    /* --- Section 9: Small-argument fast-path boundaries (8) --- */
    /* sinh(x) ~ x when |x| is tiny; implementations use thresholds at power-of-2 */
    emit_u(0x33800000u);  /* 2^-24, below linear approximation threshold */
    emit_u(0xb3800000u);  /* -2^-24 */
    emit_u(0x39800000u);  /* 2^-12 */
    emit_u(0xb9800000u);  /* -2^-12 */
    emit_u(0x3c800000u);  /* 2^-6 */
    emit_u(0xbc800000u);  /* -2^-6 */
    emit_u(0x3d800000u);  /* 2^-4 = 0.0625 */
    emit_u(0xbd800000u);  /* -2^-4 */

    /* --- Section 10: Hard/branch-coverage cases (29) --- */
    /* Fractional grid [0.125, 0.875] step 0.125, +/- (12 points) */
    emit_u(0x3e000000u);  /* 0.125 */
    emit_u(0xbe000000u);  /* -0.125 */
    emit_u(0x3e800000u);  /* 0.25 */
    emit_u(0xbe800000u);  /* -0.25 */
    emit_u(0x3ec00000u);  /* 0.375 */
    emit_u(0xbec00000u);  /* -0.375 */
    emit_u(0x3f200000u);  /* 0.625 */
    emit_u(0xbf200000u);  /* -0.625 */
    emit_u(0x3f400000u);  /* 0.75 */
    emit_u(0xbf400000u);  /* -0.75 */
    emit_u(0x3f600000u);  /* 0.875 */
    emit_u(0xbf600000u);  /* -0.875 */
    /* pi, exercises argument in pi-neighborhood */
    emit_u(0x40490fdbu);  /* pi ~ 3.1416 */
    emit_u(0xc0490fdbu);  /* -pi */
    /* Medium magnitude values */
    emit(3.0f);
    emit(-3.0f);
    emit(5.0f);
    emit(-5.0f);
    emit(8.0f);
    emit(-8.0f);
    emit(16.0f);
    emit(-16.0f);
    emit(50.0f);
    emit(-50.0f);
    /* Very small: sinh(x)~x path */
    emit_u(0x33d6bf95u);  /* 1e-7 */
    emit_u(0xb3d6bf95u);  /* -1e-7 */
    emit_u(0x38d1b717u);  /* 1e-4 */
    emit_u(0xb8d1b717u);  /* -1e-4 */
    /* log10 ~ 2.3026: exercises moderate-range polynomial */
    emit_u(0x40135d8eu);  /* log(10) ~ 2.3026 */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [0, 88.7] and [-88.7, 0] in 200 steps each */
static void test_sweep(void)
{
    float hi = 88.7f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

